description:
Assign components to zones before geometric placement.

## Location
`packages/temper-placer/src/temper_placer/topological/zone_solver.py`

## Goal
Determine which zone each component belongs to:
- Satisfy enclosing constraints
- Respect separation constraints between zones
- Handle components in multiple candidate zones

## Algorithm

This is a constraint satisfaction problem (CSP). Use backtracking with constraint propagation.

```python
from dataclasses import dataclass
from enum import Enum

class ZoneAssignmentStatus(Enum):
    UNASSIGNED = 'unassigned'
    ASSIGNED = 'assigned'
    CONFLICT = 'conflict'

@dataclass
class ZoneAssignment:
    '''Assignment of components to zones'''
    assignments: dict[str, str]  # component -> zone
    unassigned: list[str]
    conflicts: list[tuple[str, str, str]]  # (component, zone1, zone2)

class ZoneSolver:
    '''Solve zone assignment as CSP'''

    def __init__(
        self,
        zones: list[Zone],
        constraints: list[Constraint],
        components: list[str],
    ):
        self.zones = {z.name: z for z in zones}
        self.constraints = constraints
        self.components = components

        # Build component -> candidate zones map
        self.candidates = self._build_candidates()

    def _build_candidates(self) -> dict[str, set[str]]:
        '''Determine candidate zones for each component'''
        candidates = {c: set(self.zones.keys()) for c in self.components}

        for constraint in self.constraints:
            if isinstance(constraint, EnclosingConstraint):
                zone = constraint.outer
                for component in constraint.inner:
                    if component in candidates:
                        # Component MUST be in this zone
                        candidates[component] = {zone}

            elif isinstance(constraint, OnSideConstraint):
                # Restrict to zones on specified side
                valid_zones = self._zones_on_side(constraint.side, constraint.edge)
                for component in constraint.components:
                    if component in candidates:
                        candidates[component] &= valid_zones

        return candidates

    def _zones_on_side(self, side: str, edge: str | None) -> set[str]:
        '''Find zones that satisfy side/edge constraint'''
        valid = set()
        for name, zone in self.zones.items():
            if self._zone_on_side(zone, side, edge):
                valid.add(name)
        return valid

    def solve(self) -> ZoneAssignment:
        '''Solve zone assignment using backtracking'''
        assignment = {}
        unassigned = list(self.components)

        # Sort by most constrained first (MCV heuristic)
        unassigned.sort(key=lambda c: len(self.candidates[c]))

        result = self._backtrack(assignment, unassigned)

        if result is None:
            # No solution found
            return ZoneAssignment(
                assignments={},
                unassigned=self.components,
                conflicts=self._find_conflicts(),
            )

        return ZoneAssignment(
            assignments=result,
            unassigned=[],
            conflicts=[],
        )

    def _backtrack(
        self,
        assignment: dict[str, str],
        unassigned: list[str],
    ) -> dict[str, str] | None:
        '''Backtracking search'''
        if not unassigned:
            return assignment  # All assigned

        component = unassigned[0]
        remaining = unassigned[1:]

        for zone in self.candidates[component]:
            # Try assigning component to zone
            new_assignment = {**assignment, component: zone}

            # Check if assignment is consistent
            if self._is_consistent(new_assignment, component, zone):
                # Propagate constraints
                new_candidates = self._propagate(new_assignment)

                if new_candidates is not None:
                    # No domain wipeout, continue
                    old_candidates = self.candidates
                    self.candidates = new_candidates

                    result = self._backtrack(new_assignment, remaining)
                    if result is not None:
                        return result

                    self.candidates = old_candidates

        return None  # No valid assignment

    def _is_consistent(
        self,
        assignment: dict[str, str],
        component: str,
        zone: str,
    ) -> bool:
        '''Check if assignment is consistent with constraints'''
        for constraint in self.constraints:
            if isinstance(constraint, SeparatedConstraint):
                # Check if separated components are in incompatible zones
                if constraint.a == component:
                    other = constraint.b
                elif constraint.b == component:
                    other = constraint.a
                else:
                    continue

                if other in assignment:
                    other_zone = assignment[other]
                    if not self._zones_separated(zone, other_zone, constraint.min_distance_mm):
                        return False

        return True

    def _zones_separated(self, z1: str, z2: str, min_dist: float) -> bool:
        '''Check if two zones are sufficiently separated'''
        zone1 = self.zones[z1]
        zone2 = self.zones[z2]
        # Calculate zone-to-zone distance
        dist = polygon_distance(zone1.polygon, zone2.polygon)
        return dist >= min_dist
```

## Integration

```python
def assign_zones(
    pcl: PCLDocument,
    components: list[str],
) -> ZoneAssignment:
    '''Assign components to zones'''
    solver = ZoneSolver(pcl.zones, pcl.constraints, components)
    return solver.solve()
```

