```c
/**
 * @file transition_table.h
 * @brief State transition table and handler utilities
 */

#ifndef TRANSITION_TABLE_H
#define TRANSITION_TABLE_H

#include "state_machine.h"

/* State handler function type */
typedef void (*state_handler_t)(void);

/* State handler table entry */
typedef struct {
    state_handler_t entry;
    state_handler_t update;
    const char *name;
} state_handlers_t;

/* Define state handler table */
#define STATE_HANDLERS(ENTRY, UPDATE) {\
    [STATE_INIT] = { state_init_##ENTRY, state_init_##UPDATE, "INIT" },\
    [STATE_IDLE] = { state_idle_##ENTRY, state_idle_##UPDATE, "IDLE" },\
    [STATE_PAN_DET] = { state_pan_det_##ENTRY, state_pan_det_##UPDATE, "PAN_DET" },\
    [STATE_PREHEAT] = { state_preheat_##ENTRY, state_preheat_##UPDATE, "PREHEAT" },\
    [STATE_HEATING] = { state_heating_##ENTRY, state_heating_##UPDATE, "HEATING" },\
    [STATE_NO_PAN] = { state_no_pan_##ENTRY, state_no_pan_##UPDATE, "NO_PAN" },\
    [STATE_COOLDOWN] = { state_cooldown_##ENTRY, state_cooldown_##UPDATE, "COOLDOWN" },\
    [STATE_FAULT] = { state_fault_##ENTRY, state_fault_##UPDATE, "FAULT" },\
}

/* Call current state's entry handler */
static inline void call_state_entry(system_state_t state) {
    extern const state_handlers_t g_state_handlers;
    g_state_handlers[state].entry();
}

/* Call current state's update handler */
static inline void call_state_update(system_state_t state) {
    extern const state_handlers_t g_state_handlers;
    g_state_handlers[state].update();
}

/* Macro to define state with entry/update */
#define DEFINE_STATE(STATE_NAME) \
    static void state_##STATE_NAME##_entry(void); \
    static void state_##STATE_NAME##_update(void)

#endif /* TRANSITION_TABLE_H */
```

