## Problem

17 malloc/calloc/free calls scattered across firmware. No unified memory management. Issues:
- No tracking of allocations
- Potential leaks hard to detect
- No pool for small objects (buffers, etc.)
- Fragmentation with many small allocs

## Solution

Create `firmware/components/memory/pool.h` (ADDITIVE, non-breaking):

```c
/**
 * @file pool.h
 * @brief Fixed-size memory pool for small objects (ADDITIVE)
 * 
 * Provides pre-allocated pools for common sizes to reduce
 * malloc/free overhead and fragmentation.
 */

#ifndef MEMORY_POOL_H
#define MEMORY_POOL_H

#include <stdint.h>
#include <stdbool.h>

/* Pool configuration */
#define POOL_16_BYTES_COUNT  32
#define POOL_32_BYTES_COUNT  16
#define POOL_64_BYTES_COUNT  8
#define POOL_128_BYTES_COUNT  4

/* Pool block */
typedef struct {
    uint8_t data[128];
    bool allocated;
    struct MemoryPoolBlock *next;
} MemoryPoolBlock;

/* Memory pool for specific size */
typedef struct {
    MemoryPoolBlock blocks[4];  // 128-byte blocks
    uint8_t next_free;
    uint32_t block_size;
    uint32_t allocated_count;
} MemoryPool;

/* Pool manager */
typedef struct {
    MemoryPool pool_16;
    MemoryPool pool_32;
    MemoryPool pool_64;
    MemoryPool pool_128;
    uint32_t total_allocs;
    uint32_t total_frees;
    uint32_t current_usage;
} MemoryPoolManager;

/**
 * @brief Initialize all memory pools
 */
void memory_pools_init(void);

/**
 * @brief Allocate from appropriate pool
 */
void *pool_alloc(size_t size);

/**
 * @brief Free to pool
 */
void pool_free(void *ptr);

/**
 * @brief Get memory pool statistics
 */
typedef struct {
    uint32_t pool_16_allocated;
    uint32_t pool_32_allocated;
    uint32_t pool_64_allocated;
    uint32_t pool_128_allocated;
    uint32_t total_allocs;
    uint32_t total_frees;
    uint32_t fragmentation_bytes;
} PoolStats;

PoolStats pool_get_stats(void);

/**
 * @brief Check for memory leaks (allocs != frees)
 */
bool pool_has_leaks(void);

#endif /* MEMORY_POOL_H */
```

**Usage (ADDITIVE):**

```c
// Can use malloc/free as before
buffer = malloc(64);

// OR use pool for small allocations
#include "pool.h"
buffer = pool_alloc(64);
// ... use buffer
pool_free(buffer);
```

