## Problem

Firmware uses hal_get_tick_ms() directly with manual arithmetic for timers and cycle counting. Inconsistent patterns.

## Solution

Create `firmware/components/timing/timer.h` (ADDITIVE, non-breaking):

```c
/**
 * @file timer.h
 * @brief Timer and cycle counter utilities (ADDITIVE)
 * 
 * Provides consistent timing utilities for firmware.
 * Can be used alongside or instead of direct hal_get_tick_ms() calls.
 */

#ifndef TIMER_H
#define TIMER_H

#include <stdint.h>
#include <stdbool.h>
#include "hal_timer.h"

/* ================================
 * Timeout Checker
 * ================================ */

typedef struct {
    uint32_t start_ms;
    uint32_t timeout_ms;
    bool expired;
} timeout_t;

/**
 * @brief Initialize timeout checker
 */
static inline void timeout_init(timeout_t *t, uint32_t timeout_ms) {
    t->start_ms = hal_get_tick_ms();
    t->timeout_ms = timeout_ms;
    t->expired = false;
}

/**
 * @brief Check if timeout has expired
 */
static inline bool timeout_check(timeout_t *t) {
    if (t->expired) {
        return true;
    }
    uint32_t now = hal_get_tick_ms();
    t->expired = (now - t->start_ms) >= t->timeout_ms;
    return t->expired;
}

/**
 * @brief Reset timeout (restart timer)
 */
static inline void timeout_reset(timeout_t *t) {
    t->start_ms = hal_get_tick_ms();
    t->expired = false;
}

/* ================================
 * Cycle Counter
 * ================================ */

typedef struct {
    uint32_t count;
    uint32_t start_ms;
    uint32_t period_ms;
    uint32_t max_count;
    bool enabled;
} cycle_counter_t;

/**
 * @brief Initialize cycle counter
 */
static inline void cycle_counter_init(cycle_counter_t *c, uint32_t period_ms, uint32_t max_count) {
    c->count = 0;
    c->start_ms = hal_get_tick_ms();
    c->period_ms = period_ms;
    c->max_count = max_count;
    c->enabled = true;
}

/**
 * @brief Update cycle counter
 * Returns true on overflow
 */
static inline bool cycle_counter_update(cycle_counter_t *c) {
    if (!c->enabled) {
        return false;
    }
    uint32_t now = hal_get_tick_ms();
    uint32_t elapsed = now - c->start_ms;

    if (elapsed >= c->period_ms) {
        c->count++;
        c->start_ms = now;

        if (c->count >= c->max_count) {
            c->count = 0;  // Reset on overflow
            return true;
        }
    }
    return false;
}

/**
 * @brief Reset cycle counter
 */
static inline void cycle_counter_reset(cycle_counter_t *c) {
    c->count = 0;
    c->start_ms = hal_get_tick_ms();
}

/**
 * @brief Disable cycle counter
 */
static inline void cycle_counter_disable(cycle_counter_t *c) {
    c->enabled = false;
}

/* ================================
 * Elapsed Timer
 * ================================ */

typedef struct {
    uint32_t start_ms;
    bool running;
} elapsed_timer_t;

/**
 * @brief Start elapsed timer
 */
static inline void timer_start(elapsed_timer_t *t) {
    t->start_ms = hal_get_tick_ms();
    t->running = true;
}

/**
 * @brief Get elapsed time in ms
 */
static inline uint32_t timer_elapsed_ms(elapsed_timer_t *t) {
    if (!t->running) {
        return 0;
    }
    return hal_get_tick_ms() - t->start_ms;
}

/**
 * @brief Stop elapsed timer
 */
static inline uint32_t timer_stop(elapsed_timer_t *t) {
    uint32_t elapsed = timer_elapsed_ms(t);
    t->running = false;
    return elapsed;
}

/* ================================
 * Rate Limiter
 * ================================ */

typedef struct {
    uint32_t last_time_ms;
    uint32_t min_interval_ms;
} rate_limiter_t;

/**
 * @brief Check if action should be rate-limited
 */
static inline bool rate_limiter_check(rate_limiter_t *r) {
    uint32_t now = hal_get_tick_ms();
    uint32_t elapsed = now - r->last_time_ms;

    if (elapsed >= r->min_interval_ms) {
        r->last_time_ms = now;
        return true;  // Allow action
    }
    return false;  // Rate limited
}

/* ================================
 * Utility Macros
 * ================================ */

#define MS_TO_SEC(ms) ((ms) / 1000UL)
#define MS_TO_MIN(ms) (MS_TO_SEC(ms) / 60UL)
#define SECONDS_TO_MS(sec) ((sec) * 1000UL)

#define DELAY_MS(ms) hal_delay_ms(ms)

#endif /* TIMER_H */
```

