## Problem

String operations scattered across firmware with manual loops for strlen, strcmp, strcpy. Inconsistent and error-prone.

## Solution

Create `firmware/components/utils/string_utils.h` (ADDITIVE, non-breaking):

```c
/**
 * @file string_utils.h
 * @brief String utility functions (ADDITIVE, non-breaking)
 * 
 * Provides safer alternatives to standard C string functions.
 */

#ifndef STRING_UTILS_H
#define STRING_UTILS_H

#include <stdint.h>
#include <stdbool.h>
#include <string.h>

/* ================================
 * Safe String Copy
 * ================================ */

/**
 * @brief Safely copy string with explicit bounds checking
 */
static inline bool string_copy(char *dst, const char *src, size_t dst_size) {
    if (!dst || !src || dst_size == 0) {
        return false;
    }

    size_t i = 0;
    while (src[i] != '\0' && i < dst_size - 1) {
        dst[i] = src[i];
        i++;
    }

    dst[i] = '\0';  // Always null-terminate
    return true;
}

/**
 * @brief Safely copy string with automatic length detection
 */
static inline bool string_copy_auto(char *dst, const char *src, size_t dst_max) {
    if (!dst || !src) {
        return false;
    }

    size_t src_len = strlen(src);
    size_t copy_len = src_len < dst_max ? src_len : dst_max - 1;
    memcpy(dst, src, copy_len);
    dst[copy_len] = '\0';
    return true;
}

/* ================================
 * String Comparison
 * ================================ */

/**
 * @brief Case-insensitive string comparison (first N chars)
 */
static inline bool string_equals_n(
    const char *a, const char *b, size_t n
) {
    if (!a || !b) {
        return false;
    }

    for (size_t i = 0; i < n; i++) {
        if (tolower((unsigned char)a[i]) != tolower((unsigned char)b[i])) {
            return false;
        }
    }
    return true;
}

/* ================================
 * String Searching
 * ================================ */

/**
 * @brief Check if string starts with prefix (case-insensitive)
 */
static inline bool string_starts_with(
    const char *str, const char *prefix
) {
    if (!str || !prefix) {
        return false;
    }

    return string_equals_n(str, prefix, strlen(prefix));
}

/**
 * @brief Find character in string
 */
static inline const char *string_find_char(const char *str, char c) {
    if (!str) {
        return NULL;
    }

    return strchr(str, c);
}

/* ================================
 * String Formatting
 * ================================ */

/**
 * @brief Convert integer to string
 */
static inline void string_from_int(int value, char *dst, size_t dst_size) {
    snprintf(dst, dst_size, "%d", value);
}

/**
 * @brief Convert hex integer to string
 */
static inline void string_from_hex(uint32_t value, char *dst, size_t dst_size) {
    snprintf(dst, dst_size, "0x%lX", (unsigned long)value);
}

/**
 * @brief Format temperature value
 */
static inline void string_format_temp(float temp_c, char *dst, size_t dst_size) {
    snprintf(dst, dst_size, "%.1fC", temp_c);
}

/* ================================
 * String Validation
 * ================================ */

/**
 * @brief Check if string is empty or whitespace only
 */
static inline bool string_is_empty(const char *str) {
    if (!str) {
        return true;
    }

    while (*str) {
        if (!isspace((unsigned char)*str)) {
            return false;
        }
        str++;
    }

    return true;
}

/**
 * @brief Validate string is numeric (integer)
 */
static inline bool string_is_numeric(const char *str) {
    if (!str) {
        return false;
    }

    if (*str == '-' || *str == '+') {
        str++;  // Skip sign
    }

    while (*str) {
        if (!isdigit((unsigned char)*str)) {
            return false;
        }
        str++;
    }

    return *str == '\0';
}

/* ================================
 * Buffer Utilities
 * ================================ */

/**
 * @brief Zero buffer safely
 */
static inline void buffer_zero(void *buf, size_t size) {
    memset(buf, 0, size);
}

/**
 * @brief Fill buffer with byte
 */
static inline void buffer_fill(void *buf, size_t size, uint8_t value) {
    memset(buf, value, size);
}

/**
 * @brief Check if buffer is all zeros
 */
static inline bool buffer_is_zero(void *buf, size_t size) {
    uint8_t *ptr = (uint8_t *)buf;
    for (size_t i = 0; i < size; i++) {
        if (ptr[i] != 0) {
            return false;
        }
    }
    return true;
}

#endif /* STRING_UTILS_H */
