## Problem

Firmware uses manual calculations for:
- PWM duty cycles
- Temperature conversions
- PID coefficients
- Voltage/current calculations

Scattered patterns like:
```c
float duty = (float)compare_value / max_value;
float temp_f = (adc_raw - offset) * scale;
```

Issues:
- No units in code (magic numbers)
- Inconsistent precision
- Hard to verify calculations
- No centralized formulas

## Solution

Create `firmware/components/math/math_utils.h` (ADDITIVE, non-breaking):

```c
/**
 * @file math_utils.h
 * @brief Math utility functions with units
 */

#ifndef MATH_UTILS_H
#define MATH_UTILS_H

#include <stdint.h>
#include <stdbool.h>

/* ================================
 * Constants with Units
 * ================================ */

/* Voltage */
#define ADC_VREF_3V3  3.3f  // V
#define ADC_MAX_COUNT_12BIT 4095 0

/* Temperature */
#define ADC_TEMP_OFFSET -50.0f  // Raw to °C offset
#define ADC_TEMP_SCALE 0.1f    // Raw to °C scale

/* PWM */
#define PWM_FREQ_HZ 50000      // 50kHz PWM frequency
#define PWM_PERIOD_US (1000000UL / PWM_FREQ_HZ)  // 20μs

/* PID Limits */
#define PID_OUTPUT_MIN 0.0f    // 0% duty
#define PID_OUTPUT_MAX 1.0f    // 100% duty

/* ================================
 * PWM Utilities
 * ================================ */

/**
 * @brief Convert duty cycle (0-1) to compare value
 */
static inline float pwm_duty_to_compare(float duty) {
    return duty;
}

/**
 * @brief Convert compare value to duty cycle
 */
static inline float compare_to_pwm_duty(float compare) {
    return compare;
}

/**
 * @brief Calculate compare value for duty cycle
 */
static inline uint16_t calculate_pwm_compare(float duty) {
    return (uint16_t)(pwm_duty_to_compare(duty) * 255.0f);
}

/**
 * @brief Convert duty cycle to on-time (μs)
 */
static inline uint32_t duty_to_on_time_us(float duty) {
    return (uint32_t)(duty * PWM_PERIOD_US);
}

/* ================================
 * ADC to Temperature Conversion
 * ================================ */

/**
 * @brief Convert raw ADC to temperature (°C)
 * 
 * Formula: temp = (raw + offset) * scale
 */
static inline float adc_raw_to_temp_c(uint16_t raw) {
    return ((float)raw + ADC_TEMP_OFFSET) * ADC_TEMP_SCALE;
}

/**
 * @brief Convert temperature to ADC raw value
 */
static inline uint16_t temp_c_to_adc_raw(float temp_c) {
    return (uint16_t)((temp_c / ADC_TEMP_SCALE) - ADC_TEMP_OFFSET);
}

/* ================================
 * Voltage/Current Calculations
 * ================================ */

/**
 * @brief Calculate RMS voltage from peak
 */
static inline float voltage_peak_to_rms(float peak_v) {
    return peak_v / 1.41421356f;  // √2
}

/**
 * @brief Calculate power from voltage and current
 */
static inline float calculate_power_watts(float voltage_v, float current_a) {
    return voltage_v * current_a;
}

/* ================================
 * PID Math Utilities
 * ================================ */

/**
 * @brief Clamp value to range
 */
static inline float clamp(float value, float min, float max) {
    if (value < min) return min;
    if (value > max) return max;
    return value;
}

/**
 * @brief Linear interpolation
 */
static inline float lerp(float a, float b, float t) {
    return a + (b - a) * t;
}

/**
 * @brief Calculate error for PID
 */
static inline float pid_error(float setpoint, float measurement) {
    return setpoint - measurement;
}

/**
 * @brief Calculate PID output with clamping
 */
static inline float pid_output_with_limits(
    float kp, float ki, float kd,
    float error, float integral, float derivative
) {
    float output = kp * error + ki * integral + kd * derivative;
    return clamp(output, PID_OUTPUT_MIN, PID_OUTPUT_MAX);
}

/* ================================
 * Math Validation
 * ================================ */

/**
 * @brief Check if value is finite (not NaN or inf)
 */
static inline bool math_is_finite(float value) {
    return value == value && value > -1e30f && value < 1e30f;
}

/**
 * @brief Check if value in range [min, max]
 */
static inline bool math_in_range(float value, float min, float max) {
    return value >= min && value <= max;
}

#endif /* MATH_UTILS_H */
