Create bidirectional mapping between components and loops.

## Location
`packages/temper-placer/src/temper_placer/core/loop_ownership.py`

## Goal
Components need to know which loops they belong to for:
- Loss function weighting (components in critical loops get higher priority)
- Placement decisions (keep loop members close)
- Visualization (color components by loop membership)

## Data Structures

```python
from dataclasses import dataclass, field

@dataclass
class LoopMembership:
    '''A component's membership in a loop'''
    loop_name: str
    role: str  # 'switch', 'capacitor', 'driver', 'resistor', etc.
    pins_in_loop: list[str]  # Which pins participate

@dataclass
class ComponentLoopInfo:
    '''All loop information for a single component'''
    component_ref: str
    memberships: list[LoopMembership] = field(default_factory=list)

    @property
    def loop_names(self) -> list[str]:
        return [m.loop_name for m in self.memberships]

    @property
    def is_in_critical_loop(self) -> bool:
        # Would need access to loop priorities
        return any(m.loop_name.startswith('commutation') or 
                   m.loop_name.startswith('gate_drive') 
                   for m in self.memberships)

    def get_priority_weight(self, loop_collection: LoopCollection) -> float:
        '''Calculate placement priority based on loop memberships'''
        max_weight = 0.0
        for membership in self.memberships:
            loop = loop_collection.get_loop(membership.loop_name)
            if loop:
                weight = {
                    LoopPriority.CRITICAL: 1.0,
                    LoopPriority.HIGH: 0.7,
                    LoopPriority.MEDIUM: 0.4,
                    LoopPriority.LOW: 0.1,
                }.get(loop.priority, 0.0)
                max_weight = max(max_weight, weight)
        return max_weight

@dataclass
class LoopOwnershipMap:
    '''Bidirectional mapping between components and loops'''
    # Component -> loops
    component_to_loops: dict[str, ComponentLoopInfo] = field(default_factory=dict)
    # Loop -> components (redundant but convenient)
    loop_to_components: dict[str, list[str]] = field(default_factory=dict)

    def get_component_info(self, ref: str) -> ComponentLoopInfo | None:
        return self.component_to_loops.get(ref)

    def get_loop_components(self, loop_name: str) -> list[str]:
        return self.loop_to_components.get(loop_name, [])

    def get_shared_loops(self, ref_a: str, ref_b: str) -> list[str]:
        '''Find loops that contain both components'''
        loops_a = set(self.component_to_loops.get(ref_a, ComponentLoopInfo(ref_a)).loop_names)
        loops_b = set(self.component_to_loops.get(ref_b, ComponentLoopInfo(ref_b)).loop_names)
        return list(loops_a & loops_b)

    def components_share_critical_loop(self, ref_a: str, ref_b: str) -> bool:
        '''Check if two components share a critical loop'''
        shared = self.get_shared_loops(ref_a, ref_b)
        # Would check priority of each shared loop
        return len(shared) > 0
```

## Building the Map

```python
def build_ownership_map(
    loops: LoopCollection,
    netlist: Netlist,
) -> LoopOwnershipMap:
    '''
    Build bidirectional ownership map from loops and netlist.

    For each loop, identify all components and their roles.
    '''
    ownership = LoopOwnershipMap()

    for loop in loops.loops:
        component_refs = loop.get_component_refs()

        for ref in component_refs:
            # Determine role based on component type
            component = netlist.get_component(ref)
            role = classify_role(component, loop)

            # Find which pins are in this loop
            pins_in_loop = [
                pin.pin_name for pin in loop.pins 
                if pin.component_ref == ref
            ]

            membership = LoopMembership(
                loop_name=loop.name,
                role=role,
                pins_in_loop=pins_in_loop,
            )

            # Add to component -> loops map
            if ref not in ownership.component_to_loops:
                ownership.component_to_loops[ref] = ComponentLoopInfo(ref)
            ownership.component_to_loops[ref].memberships.append(membership)

            # Add to loop -> components map
            if loop.name not in ownership.loop_to_components:
                ownership.loop_to_components[loop.name] = []
            ownership.loop_to_components[loop.name].append(ref)

    return ownership

def classify_role(component: Component, loop: Loop) -> str:
    '''Classify component role in a loop'''
    if is_power_switch(component):
        return 'switch'
    elif is_capacitor(component):
        if 'bus' in component.ref.lower() or component.value_uf > 100:
            return 'bus_capacitor'
        elif 'boot' in component.ref.lower():
            return 'bootstrap_capacitor'
        else:
            return 'decoupling_capacitor'
    elif is_gate_driver(component):
        return 'driver'
    elif is_resistor(component):
        return 'gate_resistor'
    elif is_diode(component):
        return 'bootstrap_diode'
    else:
        return 'other'
```

## Integration with PlacementState

```python
# In temper_placer/core/state.py
@dataclass
class PlacementState:
    # ... existing fields ...
    loop_ownership: LoopOwnershipMap | None = None

    def get_loop_weight(self, ref: str) -> float:
        '''Get placement priority weight for component'''
        if self.loop_ownership is None:
            return 0.5  # Default weight
        info = self.loop_ownership.get_component_info(ref)
        if info is None:
            return 0.1  # Not in any loop
        return info.get_priority_weight(self.loops)
